const b = $json.body || {};
const mid = String(b.merchant_id || '');
const isUuid = /^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$/.test(mid);
let rule_set = b.rule_set;
if (typeof rule_set === 'string') { try { rule_set = JSON.parse(rule_set); } catch { return [{ json:{ payload:{ valid:false, error:'bad_rule_set_json' } } }]; } }
rule_set = rule_set || {};
const floor = String(rule_set.condition_floor || 'good');
const okFloor = ['new_with_tags','excellent','good','fair'].includes(floor);
const valid = !!(isUuid && okFloor);
return [{ json: { payload: {
  valid, error: valid ? null : (!isUuid ? 'bad_merchant_id' : 'bad_condition_floor'),
  merchant_id: mid, rule_set, operator_email: String(b.operator_email || '')
} } }];

const r = $json || {};
if (!r.valid) return [{ json: { statusCode: 400, body: { ok:false, error: r.error||'invalid' } } }];
if (!r.updated) return [{ json: { statusCode: 404, body: { ok:false, error:'not_found' } } }];
return [{ json: { statusCode: 200, body: { ok:true, slug: r.slug } } }];

const crypto = require('crypto');
const secret = $env.INTAKE_WEBHOOK_SECRET || '';
const item = ($input.first() && $input.first().json) || {};
const h = item.headers || {};
const sig = String(h['x-ttr-signature'] || '');
const ts = String(h['x-ttr-timestamp'] || '');
const body = item.body;
// Reproduce exactly what the Pages function signed: JSON.stringify(payload).
// n8n parses the JSON body into an object preserving key order, so re-stringify
// is byte-identical for compact JSON. If a string slipped through, sign as-is.
const raw = (typeof body === 'string') ? body : JSON.stringify(body == null ? {} : body);
let ok = false;
if (secret && sig && /^[0-9]+$/.test(ts)) {
  const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(ts + '.' + raw).digest('hex');
  const a = Buffer.from(sig);
  const b = Buffer.from(expected);
  const fresh = Math.abs(Date.now() - Number(ts)) < 300000; // 5 min replay window
  ok = a.length === b.length && crypto.timingSafeEqual(a, b) && fresh;
}
if (!ok) { throw new Error('unauthorized'); }
return $input.all();
